const items = $input.all();
const results = [];

for (const item of items) {
  let parsed;
  try {
    const raw = (item.json.output || '')
      .replace(/```json/g, '')
      .replace(/```/g, '')
      .trim();
    parsed = JSON.parse(raw);
  } catch (e) {
    parsed = {
      verdict: 'unknown',
      confidence: 0,
      indicators: [],
      reasoning: 'Failed to parse: ' + (item.json.output || 'no output')
    };
  }

  // source 优先从解析出的 JSON 里取（agent prompt 里要求返回 source 字段）
  // 如果 agent 没返回 source，从上游 item 取
  if (!parsed.source) {
    parsed.source = item.json.source || 'unknown';
  }

  results.push({ json: parsed });
}

return results;

const items = $input.all();

const zeek = items.find(i => i.json.source === 'zeek')?.json || {};
const suricata = items.find(i => i.json.source === 'suricata')?.json || {};

// 应用 confidence threshold 降级规则
function applyThreshold(result) {
  if (!result.verdict) return result;

  // confidence < 0.75 时 malicious 降级为 suspicious
  if (result.verdict === 'malicious' && result.confidence < 0.75) {
    return { ...result, verdict: 'suspicious', downgraded: true };
  }
  // confidence < 0.5 时 suspicious 降级为 benign
  if (result.verdict === 'suspicious' && result.confidence < 0.5) {
    return { ...result, verdict: 'benign', downgraded: true };
  }
  return result;
}

const zeekAdjusted = applyThreshold(zeek);
const suricataAdjusted = applyThreshold(suricata);

// 只有两个来源都认为是 suspicious/malicious 才上报
// 或者任一为 malicious 且 confidence >= 0.85
const bothEscalate = (
  (zeekAdjusted.verdict === 'suspicious' || zeekAdjusted.verdict === 'malicious') &&
  (suricataAdjusted.verdict === 'suspicious' || suricataAdjusted.verdict === 'malicious')
);

const highConfidenceMalicious = (
  (zeekAdjusted.verdict === 'malicious' && zeekAdjusted.confidence >= 0.85) ||
  (suricataAdjusted.verdict === 'malicious' && suricataAdjusted.confidence >= 0.85)
);

// 综合 verdict：取两者中较严重的，但受 confidence 约束
function combineVerdict(z, s) {
  const order = { malicious: 3, suspicious: 2, benign: 1, unknown: 0 };
  const zScore = order[z.verdict] || 0;
  const sScore = order[s.verdict] || 0;

  if (zScore >= sScore) return z.verdict;
  return s.verdict;
}

return [{
  json: {
    zeek: zeekAdjusted,
    suricata: suricataAdjusted,
    combinedVerdict: combineVerdict(zeekAdjusted, suricataAdjusted),
    needsEscalation : (
      zeekAdjusted.verdict === 'suspicious' || zeekAdjusted.verdict === 'malicious' ||
      suricataAdjusted.verdict === 'suspicious' || suricataAdjusted.verdict === 'malicious'
    ),
  }
}];

const raw = $input.first().json.output
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .trim();

let report;
try {
  report = JSON.parse(raw);
} catch(e) {
  return [{ json: { response: raw } }];
}

const text = `
🚨 INCIDENT REPORT — ${report.incident_id}
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
Severity : ${report.severity}
Verdict  : ${report.verdict}
Confidence: ${(report.confidence * 100).toFixed(0)}%

📋 Summary
${report.summary}

🔍 Indicators of Compromise
${(report.indicators_of_compromise || []).map(i => `• ${i}`).join('\n') || '• None identified'}

📅 Correlated Timeline
${(report.correlated_timeline || []).map(t => `• ${t}`).join('\n') || '• No timeline data'}

✅ Recommended Actions
${(report.recommended_actions || []).map(a => `• ${a}`).join('\n') || '• Continue monitoring'}

🧠 Justification
${report.justification}
`.trim();

// 自动保存
const fs = require('fs');
const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
const savePath = `/home/node/reports/incident_${timestamp}.txt`;
fs.mkdirSync('/home/node/reports', { recursive: true });
fs.writeFileSync(savePath, text, 'utf8');

return [{ json: { 
  response: text + `\n\n📁 Report auto-saved to: ${savePath}`
}}];

const msg = $input.first().json.body?.chatInput || $input.first().json.chatInput;

let zeekLogs = '';
let suricataLogs = '';

try {
  const parsed = JSON.parse(msg);
  zeekLogs = JSON.stringify(parsed.zeek || parsed.zeekLogs || '');
  suricataLogs = JSON.stringify(parsed.suricata || parsed.suricataAlerts || '');
} catch (e) {
  // 如果不是 JSON，整条消息同时传给两个 agent
  zeekLogs = msg;
  suricataLogs = msg;
}

return [
  { json: { source: 'zeek', logs: zeekLogs } },
  { json: { source: 'suricata', logs: suricataLogs } }
];
